changeSet.sql:
CREATE INDEX idx_meh_execution_context ON measure_execution_history USING GIN (execution_context);
CREATE INDEX idx_meh_error_details ON measure_execution_history USING GIN (error_details);
CREATE INDEX idx_meh_data_sources ON measure_execution_history USING GIN (data_sources);
CREATE INDEX idx_meh_overrides_applied ON measure_execution_history USING GIN (overrides_applied);

COMMENT ON TABLE measure_execution_history IS 'HIPAA COMPLIANCE: Complete audit trail of every measure calculation execution';
COMMENT ON COLUMN measure_execution_history.execution_mode IS 'SCHEDULED, MANUAL, API, BULK, RECALCULATION';
COMMENT ON COLUMN measure_execution_history.execution_status IS 'SUCCESS, FAILURE, PARTIAL, SKIPPED, TIMEOUT';
COMMENT ON COLUMN measure_execution_history.data_sources IS 'JSONB tracking which data sources were queried (FHIR resources, external APIs)';
COMMENT ON COLUMN measure_execution_history.overrides_applied IS 'JSONB of all patient overrides and profiles that were applied';

ALTER TABLE measure_execution_history
    ADD CONSTRAINT chk_meh_execution_mode
        CHECK (execution_mode IN ('SCHEDULED', 'MANUAL', 'API', 'BULK', 'RECALCULATION', 'ADHOC'));

ALTER TABLE measure_execution_history
    ADD CONSTRAINT chk_meh_execution_status
        CHECK (execution_status IN ('SUCCESS', 'FAILURE', 'PARTIAL', 'SKIPPED', 'TIMEOUT'));

ALTER TABLE measure_execution_history
    ADD CONSTRAINT chk_meh_duration
        CHECK (duration_ms IS NULL OR duration_ms >= 0);

ALTER TABLE measure_execution_history
    ADD CONSTRAINT chk_meh_data_period
        CHECK (data_period_end IS NULL OR data_period_end >= data_period_start);

rollback.sql:
ALTER TABLE measure_execution_history DROP CONSTRAINT IF EXISTS chk_meh_execution_mode;
ALTER TABLE measure_execution_history DROP CONSTRAINT IF EXISTS chk_meh_execution_status;
ALTER TABLE measure_execution_history DROP CONSTRAINT IF EXISTS chk_meh_duration;
ALTER TABLE measure_execution_history DROP CONSTRAINT IF EXISTS chk_meh_data_period;

changeSet.sql:
CREATE OR REPLACE FUNCTION calculate_execution_duration()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.end_time IS NOT NULL AND NEW.start_time IS NOT NULL THEN
        NEW.duration_ms := EXTRACT(EPOCH FROM (NEW.end_time - NEW.start_time)) * 1000;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_meh_calculate_duration
    BEFORE INSERT OR UPDATE ON measure_execution_history
    FOR EACH ROW
    EXECUTE FUNCTION calculate_execution_duration();
